"use strict";(self.webpackChunkclassic=self.webpackChunkclassic||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/docs/intro","docId":"intro"},{"type":"category","label":"Overview","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"First Steps","href":"/docs/overview/first-steps","docId":"overview/first-steps"},{"type":"link","label":"Application","href":"/docs/overview/application","docId":"overview/application"},{"type":"link","label":"App Container","href":"/docs/overview/app-container","docId":"overview/app-container"},{"type":"link","label":"Modules","href":"/docs/overview/module","docId":"overview/module"},{"type":"link","label":"Controllers","href":"/docs/overview/controller","docId":"overview/controller"},{"type":"link","label":"Use Cases","href":"/docs/overview/usecase","docId":"overview/usecase"},{"type":"link","label":"Providers","href":"/docs/overview/providers","docId":"overview/providers"},{"type":"link","label":"Repositories","href":"/docs/overview/repositories","docId":"overview/repositories"},{"type":"link","label":"Entities","href":"/docs/overview/entities","docId":"overview/entities"},{"type":"link","label":"Decorators","href":"/docs/overview/decorators","docId":"overview/decorators"},{"type":"link","label":"Dependencies","href":"/docs/overview/dependencies","docId":"overview/dependencies"}],"href":"/docs/category/overview"},{"type":"category","label":"CLI","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Expresso TS CLI Tool","href":"/docs/cli/overview","docId":"cli/overview"}],"href":"/docs/category/cli"},{"type":"category","label":"Tutorials","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Overview","href":"/docs/tutorials/overview","docId":"tutorials/overview"}],"href":"/docs/category/tutorials"},{"type":"link","label":"Roadmap","href":"/docs/roadmap","docId":"roadmap"}]},"docs":{"cli/overview":{"id":"cli/overview","title":"Expresso TS CLI Tool","description":"The Expresso TS CLI is a command-line interface tool that helps you to create ExpressoTS projects, develop, and maintain your applications and resources created. It assists in multiple ways, including scaffolding the project as well as the services offered by the application such as use cases, controllers, providers and more.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"ExpressoTS is a TypeScript lightweight framework for building scalable, readable and maintainable server-side applications.","sidebar":"tutorialSidebar"},"overview/app-container":{"id":"overview/app-container","title":"App Container","description":"The Expresso TS uses InversifyJS container as it is a powerful tool for managing dependencies in a TypeScript application. Also it is a type-aware container that can be used to manage the instantiation and resolution of objects, as well as the management of their life cycles.","sidebar":"tutorialSidebar"},"overview/application":{"id":"overview/application","title":"Application","description":"The Application Overview provides a comprehensive demonstration of the main components of an Expresso TS application. At the heart of an Expresso TS application lies the Application class, which serves as the foundation for creating and configuring the server. Additionally, the Application class makes use of the application container from Inversify that loads all the modules, including their respective routes [controllers]. This ensures a streamlined and efficient process for handling incoming requests and delivering the appropriate responses.","sidebar":"tutorialSidebar"},"overview/controller":{"id":"overview/controller","title":"Controllers","description":"Controllers act as the primary interface between the client and server in Node.js applications. They handle incoming requests, validate payloads against Input DTO, and emit responses in the DTO format output. In essence, controllers bridge the communication between clients and service layers, also known as use-cases.","sidebar":"tutorialSidebar"},"overview/decorators":{"id":"overview/decorators","title":"Decorators","description":"Here is a complete list of all the decorators that are available in Expresso TS as wel as a brief description of what they do.","sidebar":"tutorialSidebar"},"overview/dependencies":{"id":"overview/dependencies","title":"Dependencies","description":"","sidebar":"tutorialSidebar"},"overview/entities":{"id":"overview/entities","title":"Entities","description":"Entities are the core components of an Expresso TS application. They are the objects that are used to represent the data that is going to be manipulated by the application and when is necessary to be persisted in the database.","sidebar":"tutorialSidebar"},"overview/first-steps":{"id":"overview/first-steps","title":"First Steps","description":"In this section, you will delve into the core concepts of ExpressoTS. To familiarize yourself with the framework and its building blocks, we\'ll guide you through the process of building a simple non-opinionated project from scratch. This will help you understand some of the initial framework concepts and get started with ExpressoTS.","sidebar":"tutorialSidebar"},"overview/module":{"id":"overview/module","title":"Modules","description":"Before explaining what a single module is, let\'s first talk about what a container module is.","sidebar":"tutorialSidebar"},"overview/providers":{"id":"overview/providers","title":"Providers","description":"From the perspective of clean code, providers are classes or objects that are responsible for creating and managing instances of other objects. Providers act as factories that instantiate and configure objects with their dependencies, which helps to keep the code modular and flexible.","sidebar":"tutorialSidebar"},"overview/repositories":{"id":"overview/repositories","title":"Repositories","description":"The repository pattern is a design pattern commonly used in software development that provides a way to abstract the data persistence layer of an application. In TypeScript, this pattern can be implemented using classes that represent repositories, which are responsible for retrieving, storing, updating, and deleting data from a data store, such as a database.","sidebar":"tutorialSidebar"},"overview/usecase":{"id":"overview/usecase","title":"Use Cases","description":"From a UML standpoint, use cases provide a way to model the interactions between users, other systems, and a software application. A use case describes a specific scenario or flow of events between the actors and the system, leading to a certain outcome. In the context of Expresso TS, use cases serve to represent the business logic of the application, allowing for a clear separation between the controller and the request execution.","sidebar":"tutorialSidebar"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"","sidebar":"tutorialSidebar"},"tutorials/overview":{"id":"tutorials/overview","title":"Overview","description":"","sidebar":"tutorialSidebar"}}}')}}]);